#mod-fase2-1 .form-group{display:flex;flex-direction:column;gap:6px}
#mod-fase2-1 .form-group label{font-size:12px;font-weight:500;color:#94a3b8;text-transform:uppercase;letter-spacing:.5px}
#mod-fase2-1 .config-input{padding:10px 12px;border-radius:6px;border:1px solid #334155;background:#0f172a;color:#f1f5f9;font-size:13px;outline:none;width:100%}
#mod-fase2-1 .config-input:focus{border-color:#3b82f6}
#mod-fase2-1 .btn{padding:8px 16px;border-radius:6px;border:none;font-size:13px;font-weight:500;cursor:pointer;transition:.2s;display:inline-flex;align-items:center;gap:6px}
#mod-fase2-1 .btn-primary{background:#3b82f6;color:#fff}
