// FASE2_1 - Materias Primas v3.0.0
// Plugin para ERP Industrial v3.0

(function() {
  "use strict";

  var PLUGIN_ID = "FASE2_1";
  var PLUGIN_VERSION = "3.0.0";
  var editandoId = null;

  function f21_getERP() {
    return window.erp;
  }

  function f21_initDemoData() {
    var erp = f21_getERP();
    if (!erp) return;
    var db = erp.getDB();
    if (!db.materiasPrimas || db.materiasPrimas.length === 0) {
      db.materiasPrimas = [
        {id:"MP001",codigo:"MP001",nombre:"Hidroxido de Sodio",categoria:"Bases",unidad:"kg",stock:850,stockMin:200,costoUnitario:2.5,monedaCosto:"USD",descripcion:"Base quimica para formulacion de desinfectantes",estado:"Activo",fechaCreacion:new Date().toISOString()},
        {id:"MP002",codigo:"MP002",nombre:"Acido Clorhidrico",categoria:"Acidos",unidad:"L",stock:420,stockMin:100,costoUnitario:1.8,monedaCosto:"USD",descripcion:"Acido industrial para procesos de limpieza",estado:"Activo",fechaCreacion:new Date().toISOString()},
        {id:"MP003",codigo:"MP003",nombre:"Hipoclorito de Sodio",categoria:"Desinfectantes",unidad:"L",stock:600,stockMin:150,costoUnitario:1.2,monedaCosto:"USD",descripcion:"Desinfectante base para productos terminados",estado:"Activo",fechaCreacion:new Date().toISOString()},
        {id:"MP004",codigo:"MP004",nombre:"Envase Plastico 1L",categoria:"Empaque",unidad:"und",stock:1200,stockMin:300,costoUnitario:0.45,monedaCosto:"USD",descripcion:"Envase plastico HDPE de 1 litro con tapa",estado:"Activo",fechaCreacion:new Date().toISOString()},
        {id:"MP005",codigo:"MP005",nombre:"Lauril Eter Sulfato",categoria:"Bases",unidad:"kg",stock:350,stockMin:100,costoUnitario:3.2,monedaCosto:"USD",descripcion:"Tensioactivo para formulacion de detergentes",estado:"Activo",fechaCreacion:new Date().toISOString()}
      ];
      erp.saveLocal(db);
      erp.showToast("info","Datos Demo","5 materiales de ejemplo cargados");
    }
  }

  function f21_renderTabla() {
    var erp = f21_getERP();
    if (!erp) return;
    var db = erp.getDB();
    var materiales = db.materiasPrimas || [];
    var buscarEl = document.getElementById("f21-buscar");
    var filtroCatEl = document.getElementById("f21-filtro-cat");
    var filtroStockEl = document.getElementById("f21-filtro-stock");
    var buscar = buscarEl ? buscarEl.value.toLowerCase() : "";
    var filtroCat = filtroCatEl ? filtroCatEl.value : "";
    var filtroStock = filtroStockEl ? filtroStockEl.value : "";
    var tbody = document.querySelector("#f21-tabla tbody");
    if (!tbody) return;

    var filtrados = materiales.filter(function(m) {
      if (buscar && m.nombre.toLowerCase().indexOf(buscar) === -1 && m.codigo.toLowerCase().indexOf(buscar) === -1 && m.categoria.toLowerCase().indexOf(buscar) === -1) return false;
      if (filtroCat && m.categoria !== filtroCat) return false;
      if (filtroStock === "bajo" && m.stock > m.stockMin) return false;
      if (filtroStock === "ok" && m.stock <= m.stockMin) return false;
      return true;
    });

    var contador = document.getElementById("f21-contador");
    if (contador) contador.textContent = filtrados.length + " de " + materiales.length + " materiales";

    var totalValor = 0;
    filtrados.forEach(function(m) { totalValor += (m.stock * m.costoUnitario); });
    var totalEl = document.getElementById("f21-total-valor");
    if (totalEl) totalEl.textContent = "Valor total: " + erp.formatearMoneda(totalValor, "USD");

    if (filtrados.length === 0) {
      tbody.innerHTML = '<tr><td colspan="10" style="text-align:center;color:#94a3b8;padding:40px">No hay materiales. Haz clic en "Agregar Material".</td></tr>';
      return;
    }

    var html = "";
    filtrados.forEach(function(m) {
      var stockClass = m.stock <= m.stockMin ? "badge-danger" : "badge-success";
      var stockText = m.stock <= m.stockMin ? "CRITICO" : "OK";
      var costoFormateado = erp.formatearMoneda(m.costoUnitario, m.monedaCosto);
      html += '<tr>' +
        '<td><strong>' + m.codigo + '</strong></td>' +
        '<td>' + m.nombre + '</td>' +
        '<td><span class="badge" style="background:rgba(59,130,246,0.15);color:#3b82f6">' + m.categoria + '</span></td>' +
        '<td>' + m.unidad + '</td>' +
        '<td><strong>' + m.stock.toLocaleString("es-VE",{minimumFractionDigits:2}) + '</strong></td>' +
        '<td>' + m.stockMin.toLocaleString("es-VE",{minimumFractionDigits:2}) + '</td>' +
        '<td>' + costoFormateado + '</td>' +
        '<td>' + m.monedaCosto + '</td>' +
        '<td><span class="badge ' + stockClass + '">' + stockText + '</span></td>' +
        '<td class="actions">' +
          '<button class="btn btn-primary btn-sm f21-btn-edit" data-id="' + m.id + '" title="Editar"><i class="fas fa-edit"></i></button> ' +
          '<button class="btn btn-danger btn-sm f21-btn-del" data-id="' + m.id + '" title="Eliminar"><i class="fas fa-trash"></i></button>' +
        '</td>' +
      '</tr>';
    });
    tbody.innerHTML = html;
  }

  function f21_setupEventDelegation() {
    var tbody = document.querySelector("#f21-tabla tbody");
    if (!tbody) return;
    tbody.addEventListener("click", function(e) {
      var btn = e.target.closest(".f21-btn-edit");
      if (btn) {
        window.f21_editarMaterial(btn.getAttribute("data-id"));
        return;
      }
      btn = e.target.closest(".f21-btn-del");
      if (btn) {
        window.f21_eliminarMaterial(btn.getAttribute("data-id"));
        return;
      }
    });
  }

  function f21_cargarSelects() {
    var erp = f21_getERP();
    if (!erp) return;
    var db = erp.getDB();
    var categorias = db.categorias || [];
    var unidades = db.unidades || [];

    var selFiltro = document.getElementById("f21-filtro-cat");
    if (selFiltro) {
      var opts = '<option value="">Todas</option>';
      categorias.forEach(function(c) { opts += '<option value="' + c.nombre + '">' + c.nombre + '</option>'; });
      selFiltro.innerHTML = opts;
    }

    var selCat = document.getElementById("f21-categoria");
    if (selCat) {
      var opts2 = '';
      categorias.forEach(function(c) { opts2 += '<option value="' + c.nombre + '">' + c.nombre + '</option>'; });
      selCat.innerHTML = opts2;
    }

    var selUnidad = document.getElementById("f21-unidad");
    if (selUnidad) {
      var opts3 = '';
      unidades.forEach(function(u) { opts3 += '<option value="' + u.simbolo + '">' + u.nombre + ' (' + u.simbolo + ')</option>'; });
      selUnidad.innerHTML = opts3;
    }
  }

  window.f21_mostrarFormulario = function(id) {
    editandoId = id || null;
    var modal = document.getElementById("f21-modal");
    var titulo = document.getElementById("f21-modal-titulo");
    if (!modal || !titulo) return;
    f21_cargarSelects();
    var erp = f21_getERP();
    if (!erp) return;

    if (editandoId) {
      var db = erp.getDB();
      var m = (db.materiasPrimas || []).find(function(x) { return x.id === editandoId; });
      if (!m) return;
      titulo.innerHTML = '<i class="fas fa-edit"></i> Editar Material';
      document.getElementById("f21-codigo").value = m.codigo;
      document.getElementById("f21-nombre").value = m.nombre;
      document.getElementById("f21-categoria").value = m.categoria;
      document.getElementById("f21-unidad").value = m.unidad;
      document.getElementById("f21-stock").value = m.stock;
      document.getElementById("f21-stock-min").value = m.stockMin;
      document.getElementById("f21-costo").value = m.costoUnitario;
      document.getElementById("f21-moneda").value = m.monedaCosto;
      document.getElementById("f21-descripcion").value = m.descripcion || "";
    } else {
      titulo.innerHTML = '<i class="fas fa-plus-circle"></i> Agregar Material';
      document.getElementById("f21-codigo").value = erp.genId("MP");
      document.getElementById("f21-nombre").value = "";
      document.getElementById("f21-stock").value = "0";
      document.getElementById("f21-stock-min").value = "0";
      document.getElementById("f21-costo").value = "0";
      document.getElementById("f21-moneda").value = "USD";
      document.getElementById("f21-descripcion").value = "";
    }
    modal.style.display = "flex";
    setTimeout(function() { modal.classList.add("active"); }, 10);
  };

  window.f21_cerrarModal = function() {
    var modal = document.getElementById("f21-modal");
    if (modal) {
      modal.classList.remove("active");
      setTimeout(function() { modal.style.display = "none"; }, 200);
    }
    editandoId = null;
  };

  window.f21_guardarMaterial = function() {
    var erp = f21_getERP();
    if (!erp) return;
    var nombre = document.getElementById("f21-nombre").value.trim();
    var categoria = document.getElementById("f21-categoria").value;
    var unidad = document.getElementById("f21-unidad").value;
    var stock = parseFloat(document.getElementById("f21-stock").value) || 0;
    var stockMin = parseFloat(document.getElementById("f21-stock-min").value) || 0;
    var costo = parseFloat(document.getElementById("f21-costo").value) || 0;
    var moneda = document.getElementById("f21-moneda").value;
    var descripcion = document.getElementById("f21-descripcion").value.trim();

    if (!nombre) { erp.showToast("error","Error","El nombre es obligatorio"); return; }
    if (!categoria) { erp.showToast("error","Error","Selecciona una categoria"); return; }
    if (!unidad) { erp.showToast("error","Error","Selecciona una unidad"); return; }

    var db = erp.getDB();
    if (!db.materiasPrimas) db.materiasPrimas = [];

    if (editandoId) {
      var idx = db.materiasPrimas.findIndex(function(m) { return m.id === editandoId; });
      if (idx >= 0) {
        db.materiasPrimas[idx].nombre = nombre;
        db.materiasPrimas[idx].categoria = categoria;
        db.materiasPrimas[idx].unidad = unidad;
        db.materiasPrimas[idx].stock = stock;
        db.materiasPrimas[idx].stockMin = stockMin;
        db.materiasPrimas[idx].costoUnitario = costo;
        db.materiasPrimas[idx].monedaCosto = moneda;
        db.materiasPrimas[idx].descripcion = descripcion;
        erp.showToast("success","Actualizado",nombre + " modificado");
      }
    } else {
      var codigo = document.getElementById("f21-codigo").value;
      db.materiasPrimas.push({
        id: codigo, codigo: codigo, nombre: nombre, categoria: categoria, unidad: unidad,
        stock: stock, stockMin: stockMin, costoUnitario: costo, monedaCosto: moneda,
        descripcion: descripcion, estado: "Activo", fechaCreacion: new Date().toISOString()
      });
      erp.showToast("success","Agregado",nombre + " registrado");
    }
    erp.saveLocal(db);
    window.f21_cerrarModal();
    f21_renderTabla();
  };

  window.f21_editarMaterial = function(id) {
    window.f21_mostrarFormulario(id);
  };

  window.f21_eliminarMaterial = function(id) {
    var erp = f21_getERP();
    if (!erp) return;
    var db = erp.getDB();
    var m = (db.materiasPrimas || []).find(function(x) { return x.id === id; });
    if (!m) return;
    erp.showConfirm("Eliminar Material","¿Eliminar " + m.nombre + "? Esta accion no se puede deshacer.",function() {
      db.materiasPrimas = (db.materiasPrimas || []).filter(function(x) { return x.id !== id; });
      erp.saveLocal(db);
      f21_renderTabla();
      erp.showToast("info","Eliminado",m.nombre + " removido");
    });
  };

  window.f21_exportarCSV = function() {
    var erp = f21_getERP();
    if (!erp) return;
    var db = erp.getDB();
    var materiales = db.materiasPrimas || [];
    if (materiales.length === 0) { erp.showToast("warning","Sin datos","No hay materiales para exportar"); return; }
    var csv = "Codigo,Nombre,Categoria,Unidad,Stock,Stock Min,Costo Unit,Moneda,Estado\n";
    materiales.forEach(function(m) {
      csv += m.codigo + "," + m.nombre + "," + m.categoria + "," + m.unidad + "," + m.stock + "," + m.stockMin + "," + m.costoUnitario + "," + m.monedaCosto + "," + m.estado + "\n";
    });
    var blob = new Blob([csv], {type: "text/csv;charset=utf-8;"});
    var url = URL.createObjectURL(blob);
    var a = document.createElement("a");
    a.href = url;
    a.download = "MateriasPrimas_" + new Date().toISOString().split("T")[0] + ".csv";
    a.click();
    URL.revokeObjectURL(url);
    erp.showToast("success","Export OK","CSV descargado");
  };

  function f21_init() {
    f21_initDemoData();
    f21_cargarSelects();
    f21_setupEventDelegation();
    f21_renderTabla();
  }

  // REGISTRAR PLUGIN
  var erp = f21_getERP();
  if (erp && erp.registerPlugin) {
    erp.registerPlugin({
      id: PLUGIN_ID,
      version: PLUGIN_VERSION,
      init: function(api) {
        f21_init();
      },
      onShow: function(api) {
        f21_renderTabla();
        f21_cargarSelects();
      }
    });
    console.log("[FASE2_1] Plugin registrado correctamente");
  } else {
    console.error("[FASE2_1] ERP no disponible para registrar plugin");
  }
})();
